/*
 * Stack Implementation in C using Struct
 * Array-based implementation with overflow/underflow handling
 * university 2022 Scheme - Data Structures
 */

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX 100 // Maximum stack size

// Stack structure definition
typedef struct {
 int data[MAX];
 int top; // Index of top element, -1 when empty
} Stack;

// Function prototypes
void initStack(Stack *s);
bool isEmpty(Stack *s);
bool isFull(Stack *s);
void push(Stack *s, int value);
int pop(Stack *s);
int peek(Stack *s);
void display(Stack *s);

// Initialize stack
void initStack(Stack *s) {
 s->top = -1; // -1 indicates empty stack
}

// Check if stack is empty - O(1)
bool isEmpty(Stack *s) {
 return (s->top == -1);
}

// Check if stack is full - O(1)
bool isFull(Stack *s) {
 return (s->top == MAX - 1);
}

// Push operation - O(1)
void push(Stack *s, int value) {
 if (isFull(s)) {
 printf("Stack Overflow! Cannot push %d\n", value);
 return;
 }
 s->top++;
 s->data[s->top] = value;
 printf("Pushed %d to stack\n", value);
}

// Pop operation - O(1)
int pop(Stack *s) {
 if (isEmpty(s)) {
 printf("Stack Underflow! Cannot pop\n");
 return -1; // Error value
 }
 int value = s->data[s->top];
 s->top--;
 return value;
}

// Peek operation - returns top without removing - O(1)
int peek(Stack *s) {
 if (isEmpty(s)) {
 printf("Stack is empty!\n");
 return -1;
 }
 return s->data[s->top];
}

// Display stack contents
void display(Stack *s) {
 if (isEmpty(s)) {
 printf("Stack is empty.\n");
 return;
 }
 printf("Stack (top to bottom): ");
 for (int i = s->top; i >= 0; i--) {
 printf("%d ", s->data[i]);
 }
 printf("\n");
}

// Main function demonstrating stack operations
int main() {
 Stack s;
 initStack(&s);

 printf("=================================\n");
 printf("STACK DEMONSTRATION - LIFO Principle\n");
 printf("=================================\n");

 // Push elements onto stack
 printf("\n--- Pushing elements ---\n");
 push(&s, 10);
 push(&s, 20);
 push(&s, 30);

 // Display current stack
 display(&s); // Output: 30 20 10

 // Peek at top
 printf("\nPeek: %d\n", peek(&s)); // Output: 30

 // Pop elements - demonstrates LIFO
 printf("\n--- Popping elements (Last In, First Out) ---\n");
 printf("Popped: %d\n", pop(&s)); // Output: 30
 printf("Popped: %d\n", pop(&s)); // Output: 20
 printf("Popped: %d\n", pop(&s)); // Output: 10

 // Display after pops
 display(&s); // Stack is empty

 // Test underflow
 printf("\n--- Testing Underflow ---\n");
 pop(&s); // Should print Stack Underflow

 // Test overflow with small stack
 printf("\n--- Testing Overflow ---\n");
 Stack small;
 initStack(&small);

 #define SMALL_MAX 3
 // Manual test for overflow (using array)
 for (int i = 0; i <= SMALL_MAX; i++) {
 if (small.top < SMALL_MAX - 1) {
 small.top++;
 small.data[small.top] = i * 10;
 printf("Pushed %d\n", i * 10);
 } else {
 printf("Stack Overflow! Cannot push %d\n", i * 10);
 }
 }

 return 0;
}

