#include <string.h>

void reverseString(char *str) {
 Stack s;
 initStack(&s);

 int len = strlen(str);

 // Push all characters
 for (int i = 0; i < len; i++) {
 push(&s, str[i]);
 }

 // Pop to reverse
 for (int i = 0; i < len; i++) {
 str[i] = pop(&s);
 }
}

/*
 * ============================================
 * Application: Parenthesis Matching
 * ============================================
 */

int isMatchingPair(char open, char close) {
 return (open == '(' && close == ')') ||
 (open == '{' && close == '}') ||
 (open == '[' && close == ']');
}

int isBalanced(const char *expr) {
 Stack s;
 initStack(&s);

 for (int i = 0; expr[i] != '\0'; i++) {
 char ch = expr[i];

 if (ch == '(' || ch == '{' || ch == '[') {
 push(&s, ch); // Push opening brackets
 } 
 else if (ch == ')' || ch == '}' || ch == ']') {
 if (isEmpty(&s)) {
 return 0; // No matching open bracket
 }
 char top = pop(&s);
 if (!isMatchingPair(top, ch)) {
 return 0; // Mismatched brackets
 }
 }
 }

 return isEmpty(&s); // Should be empty if balanced
}

// Additional main to test balanced parentheses
void test_balancing() {
 printf("\n=================================\n");
 printf("PARENTHESIS MATCHING DEMO\n");
 printf("=================================\n");

 char *expr1 = "{[A + B] * (C - D)}";
 char *expr2 = "{[A + B) * (C - D)}";

 printf("%s : %s\n", expr1, isBalanced(expr1) ? "Balanced" : "Not Balanced");
 printf("%s : %s\n", expr2, isBalanced(expr2) ? "Balanced" : "Not Balanced");
}

/*
 * Stack Implementation in Java
 * Demonstrates LIFO (Last In, First Out) principle
 * university 2022 Scheme - Data Structures
 */

import java.util.EmptyStackException;

public class Stack {
 private int[] stackArray;
 private int top; // Index of top element
 private int maxSize; // Maximum capacity

 // Constructor - initialize stack with given size
 public Stack(int size) {
 this.maxSize = size;
 this.stackArray = new int[maxSize];
 this.top = -1; // -1 indicates empty stack
 }

 // Check if stack is empty - O(1)
 public boolean isEmpty() {
 return top == -1;
 }

 // Check if stack is full - O(1)
 public boolean isFull() {
 return top == maxSize - 1;
 }

 // Push operation - O(1)
 public void push(int value) {
 if (isFull()) {
 System.out.println("Stack Overflow! Cannot push " + value);
 return;
 }
 stackArray[++top] = value;
 System.out.println("Pushed " + value + " to stack");
 }

 // Pop operation - O(1)
 public int pop() {
 if (isEmpty()) {
 System.out.println("Stack Underflow! Cannot pop");
 throw new EmptyStackException();
 }
 return stackArray[top--];
 }

 // Peek operation - returns top without removing - O(1)
 public int peek() {
 if (isEmpty()) {
 System.out.println("Stack is empty!");
 throw new EmptyStackException();
 }
 return stackArray[top];
 }

 // Get current size - O(1)
 public int size() {
 return top + 1;
 }

 // Display stack contents
 public void display() {
 if (isEmpty()) {
 System.out.println("Stack is empty.");
 return;
 }
 System.out.print("Stack (top to bottom): ");
 for (int i = top; i >= 0; i--) {
 System.out.print(stackArray[i] + " ");
 }
 System.out.println();
 }

 // Main method - demonstration
 public static void main(String[] args) {
 System.out.println("========================================");
 System.out.println("STACK DEMONSTRATION - LIFO Principle");
 System.out.println("========================================");

 Stack stack = new Stack(10);

 // Push elements
 System.out.println("\n--- Pushing elements ---");
 stack.push(10);
 stack.push(20);
 stack.push(30);

 // Display stack
 stack.display(); // Output: 30 20 10

 // Peek at top
 System.out.println("\nPeek: " + stack.peek()); // Output: 30

 // Pop elements - demonstrates LIFO
 System.out.println("\n--- Popping elements (Last In, First Out) ---");
 System.out.println("Popped: " + stack.pop()); // Output: 30
 System.out.println("Popped: " + stack.pop()); // Output: 20
 System.out.println("Popped: " + stack.pop()); // Output: 10

 // Display after pops
 stack.display(); // Stack is empty

 // Test underflow
 System.out.println("\n--- Testing Underflow ---");
 try {
 stack.pop();
 } catch (EmptyStackException e) {
 System.out.println("Caught: Stack Underflow!");
 }
 }
}

/*
 * ============================================
 * Application: String Reversal using Stack
 * ============================================
 */
class StringReversal {

 public static String reverseString(String input) {
 Stack stack = new Stack(input.length());

 // Push all characters
 for (char c : input.toCharArray()) {
 stack.push((int) c);
 }

 // Pop to reverse
 StringBuilder reversed = new StringBuilder();
 while (!stack.isEmpty()) {
 reversed.append((char) stack.pop());
 }

 return reversed.toString();
 }

 public static void main(String[] args) {
 System.out.println("\n========================================");
 System.out.println("STRING REVERSAL USING STACK");
 System.out.println("========================================");

 String original = "CSE 2022";
 String reversed = reverseString(original);

 System.out.println("Original: " + original);
 System.out.println("Reversed: " + reversed);
 }
}

/*
 * ============================================
 * Application: Parenthesis Matching
 * ============================================
 */
class ParenthesisMatching {

 private static boolean isMatchingPair(char open, char close) {
 return (open == '(' && close == ')') ||
 (open == '{' && close == '}') ||
 (open == '[' && close == ']');
 }

 public static boolean isBalanced(String expr) {
 Stack stack = new Stack(expr.length());

 for (char ch : expr.toCharArray()) {
 if (ch == '(' || ch == '{' || ch == '[') {
 stack.push(ch); // Push opening brackets
 } else if (ch == ')' || ch == '}' || ch == ']') {
 if (stack.isEmpty()) {
 return false; // No matching open bracket
 }
 char top = (char) stack.pop();
 if (!isMatchingPair(top, ch)) {
 return false; // Mismatched brackets
 }
 }
 }

 return stack.isEmpty(); // Should be empty if balanced
 }

 public static void main(String[] args) {
 System.out.println("\n========================================");
 System.out.println("PARENTHESIS MATCHING DEMO");
 System.out.println("========================================");

 String expr1 = "{[A + B] * (C - D)}";
 String expr2 = "{[A + B) * (C - D)}";

 System.out.println(expr1 + " : " + 
 (isBalanced(expr1) ? "Balanced" : "Not Balanced"));
 System.out.println(expr2 + " : " + 
 (isBalanced(expr2) ? "Balanced" : "Not Balanced"));
 }
}
